  } catch (error) {
    if (token.cancelled) return;
    if (error.name === 'PathfindingNoPath') {
      console.error('No path found to (' + targetPosition.x + ', ' + targetPosition.z + ')');
    } else if (error.name !== 'Cancelled') {
      console.error('Movement failed to (' + targetPosition.x + ', ' + targetPosition.z + '):', error);
    }
  }
});
return "<MOVING>: Moving to x:" + args.x + ", z:" + args.z + " with radius " + radius + ".";"
}
